// KI-Text-Erkennung via Sapling AI-Detection (Wahrscheinlichkeit KI-generiert).
async function run(input) {
  const text = String((input && input.text) || '').trim();
  const apiKey = String((input && input.apiKey) || '').trim();
  if (text.length < 50) return { fehler: 'Bitte mindestens ~50 Zeichen Text zur Pruefung angeben.' };
  if (!apiKey) return { fehler: 'Sapling API-Key noetig (Gratis-Tier auf sapling.ai).' };
  const res = await fetch('https://api.sapling.ai/api/v1/aidetect', {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify({ key: apiKey, text: text })
  });
  const d = await res.json();
  const score = d.score;
  if (score == null) return { fehler: (d.msg || d.message) || 'Pruefung fehlgeschlagen.' };
  return {
    kiWahrscheinlichkeit: Math.round(score * 1000) / 1000,
    prozent: Math.round(score * 100) + '%',
    einschaetzung: score >= 0.5 ? 'wahrscheinlich KI-generiert' : 'wahrscheinlich menschlich geschrieben',
    geprüfteZeichen: text.length
  };
}
